INSERT INTO notes (id, title, description) VALUES
(1, 'REST API Basics #1', 'Introduction to RESTful APIs, resources, HTTP methods, status codes, idempotency, and practical CRUD design. This note is used in teaching examples and backend exercises, where students build a small Node.js service. Example index 1.'),
(2, 'WebSocket Communication #2', 'Real-time bidirectional communication over a persistent connection for chat, dashboards, gaming, and collaboration. This note is relevant for distributed systems and web engineering, where a frontend client consumes the endpoint. Example index 2.'),
